<h3>Kelola Pembayaran</h3><table class="table"><thead><tr><th>Order</th><th>Pembeli</th><th>Metode</th><th>Bukti</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php while($p=mysqli_fetch_assoc($payments)): ?><tr><td><?=e($p['order_number'])?></td><td><?=e($p['buyer_name'])?></td><td><?=e($p['payment_method'])?></td><td><?php if($p['proof']): ?><a target="_blank" href="src/uploads/payments/<?=e($p['proof'])?>">Lihat</a><?php endif; ?></td><td><?=e($p['status'])?></td><td><?php if($p['status']!=='Dikonfirmasi'): ?><a class="btn btn-sm btn-success" href="index.php?page=admin-confirm-payment&id=<?=$p['id']?>">Konfirmasi</a><?php endif; ?></td></tr><?php endwhile; ?></tbody></table>
